283	      continue;
284	    }
285	
286	    // Determine file_type from extension
287	    const ext = filename.split(".").pop()?.toLowerCase() ?? "";
288	    const extMap: Record<string, string> = { psd: "psd", ai: "ai", jpg: "jpg", jpeg: "jpg", png: "png", pdf: "pdf" };
289	    const fileType = extMap[ext] ?? "jpg";
290	
291	    const { data: inserted, error: insertErr } = await db
292	      .from("assets")
293	      .insert({
294	        relative_path: relativePath,
295	        filename,
296	        file_type: fileType,
297	        file_size: fileSize,
298	        modified_at: now,
299	        quick_hash: `sibling_${relativePath}`,
300	        quick_hash_version: 0,
301	        thumbnail_url: thumbnailUrl,
302	        style_group_id: styleGroupId,
303	        sku: sg.sku,
304	        last_seen_at: now,
305	        ingested_at: now,
306	      })
307	      .select("id")
308	      .single();
309	
310	    if (insertErr) {
311	      results.push({ filename, action: "error", error: insertErr.message });
312	    } else {
313	      results.push({ filename, action: "created", asset_id: inserted.id });
314	    }
315	  }
316	
317	  // Refresh style group counts
318	  const groupIds = [styleGroupId];
319	  try {
320	    await db.rpc("refresh_style_group_counts_batch", { p_group_ids: groupIds });
321	    await db.rpc("refresh_style_group_primaries", { p_group_ids: groupIds });
322	  } catch (e) {
323	    console.warn("Failed to refresh style group stats:", e);
324	  }
325	
326	  const created = results.filter((r) => r.action === "created").length;
327	  const linked = results.filter((r) => r.action === "linked").length;
328	  const errors = results.filter((r) => r.action === "error").length;
329	
330	  return json({ ok: true, results, summary: { created, linked, errors } });
331	}
