      const sku = skuMap.get(r.asset_id as string);
      if (!sku) continue;
      const fileNames = parseFilesUsedFromText(r.extracted_text as string);
      for (const fn of fileNames) {
        filesUsedRows.push({ sku, file_name: fn });
      }
